package grc721

import (
	"chain"
	"math/overflow"
	"strconv"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"
)

type BasicNFT struct {
	name              string
	symbol            string
	origRealm         string   // owning realm's package path
	owners            avl.Tree // tokenId -> OwnerAddress
	balances          avl.Tree // OwnerAddress -> TokenCount
	tokenApprovals    avl.Tree // TokenId -> ApprovedAddress
	tokenURIs         avl.Tree // TokenId -> URIs
	operatorApprovals avl.Tree // "OwnerAddress:OperatorAddress" -> bool
}

func NewBasicNFT(_ int, rlm realm, name, symbol string) *BasicNFT {
	if !rlm.IsCurrent() {
		panic(ErrSpoofedRealm)
	}
	pkgPath := rlm.PkgPath()
	if pkgPath == "" {
		panic(ErrNotRealm)
	}
	if !validName(name) {
		panic(ErrInvalidName)
	}
	if !validSymbol(symbol) {
		panic(ErrInvalidSymbol)
	}

	return &BasicNFT{
		name:      name,
		symbol:    symbol,
		origRealm: pkgPath,

		owners:            avl.Tree{},
		balances:          avl.Tree{},
		tokenApprovals:    avl.Tree{},
		tokenURIs:         avl.Tree{},
		operatorApprovals: avl.Tree{},
	}
}

func (s *BasicNFT) Name() string      { return s.name }
func (s *BasicNFT) Symbol() string    { return s.symbol }
func (s *BasicNFT) TokenCount() int64 { return int64(s.owners.Size()) }

func (s *BasicNFT) ID() string {
	return s.origRealm + "." + s.symbol
}

// BalanceOf returns balance of input address
func (s *BasicNFT) BalanceOf(addr address) (int64, error) {
	if err := isValidAddress(addr); err != nil {
		return 0, err
	}

	balance := s.balances.Get(addr.String())
	if balance == nil {
		return 0, nil
	}

	return balance.(int64), nil
}

// OwnerOf returns owner of input token id
func (s *BasicNFT) OwnerOf(tid TokenID) (address, error) {
	owner := s.owners.Get(string(tid))
	if owner == nil {
		return "", ErrInvalidTokenId
	}

	return owner.(address), nil
}

// TokenURI returns the URI of input token id
func (s *BasicNFT) TokenURI(tid TokenID) (string, error) {
	uri := s.tokenURIs.Get(tid.String())
	if uri == nil {
		return "", ErrInvalidTokenId
	}

	return uri.(string), nil
}

// SetTokenURI sets the URI of a token. caller must equal the token's
// owner. The owning realm's public wrapper is responsible for deriving
// caller from rlm.Previous().Address() under an rlm.IsCurrent() guard
// before invoking this method; this method trusts the supplied caller.
func (s *BasicNFT) SetTokenURI(caller address, tid TokenID, tURI TokenURI) (bool, error) {
	// check for invalid TokenID
	if !s.exists(tid) {
		return false, ErrInvalidTokenId
	}

	// check for the right owner
	owner, err := s.OwnerOf(tid)
	if err != nil {
		return false, err
	}
	if caller != owner {
		return false, ErrCallerIsNotOwner
	}
	s.tokenURIs.Set(tid.String(), tURI.String())

	chain.Emit(
		TokenURIUpdateEvent,
		"token", s.ID(),
		"tokenId", tid.String(),
	)

	return true, nil
}

// IsApprovedForAll returns true if operator is approved for all by the owner.
// Otherwise, returns false
func (s *BasicNFT) IsApprovedForAll(owner, operator address) bool {
	key := owner.String() + ":" + operator.String()
	approved := s.operatorApprovals.Get(key)
	if approved == nil {
		return false
	}

	return approved.(bool)
}

// Approve approves the input address for a particular token. caller
// must be the owner OR an operator approved for all on owner's behalf.
// The owning realm's wrapper validates IsCurrent and derives caller
// from rlm.Previous().Address() before calling.
func (s *BasicNFT) Approve(caller, to address, tid TokenID) error {
	if err := isValidAddress(to); err != nil {
		return err
	}

	owner, err := s.OwnerOf(tid)
	if err != nil {
		return err
	}
	if owner == to {
		return ErrApprovalToCurrentOwner
	}

	if caller != owner && !s.IsApprovedForAll(owner, caller) {
		return ErrCallerIsNotOwnerOrApproved
	}

	tidStr := tid.String()
	s.tokenApprovals.Set(tidStr, to)

	chain.Emit(
		ApprovalEvent,
		"token", s.ID(),
		"owner", owner.String(),
		"to", to.String(),
		"tokenId", tidStr,
	)

	return nil
}

// GetApproved return the approved address for token
func (s *BasicNFT) GetApproved(tid TokenID) (address, error) {
	addr := s.tokenApprovals.Get(tid.String())
	if addr == nil {
		return zeroAddress, ErrTokenIdNotHasApproved
	}

	return addr.(address), nil
}

// SetApprovalForAll grants/revokes operator permission across all of
// the caller's tokens. caller is the owner whose approvals are mutated;
// the owning realm's wrapper derives it from rlm.Previous().Address()
// under an IsCurrent() guard.
func (s *BasicNFT) SetApprovalForAll(caller, operator address, approved bool) error {
	if err := isValidAddress(operator); err != nil {
		return ErrInvalidAddress
	}
	return s.setApprovalForAll(caller, operator, approved)
}

// SafeTransferFrom transfers a token from `from` to `to`, checking that
// contract recipients are aware of the GRC721 protocol to prevent
// tokens from being forever locked. caller must be the owner or an
// approved operator. The owning realm's wrapper derives caller from
// rlm.Previous().Address() under an IsCurrent() guard.
func (s *BasicNFT) SafeTransferFrom(caller, from, to address, tid TokenID) error {
	if !s.isApprovedOrOwner(caller, tid) {
		return ErrCallerIsNotOwnerOrApproved
	}

	err := s.transfer(from, to, tid)
	if err != nil {
		return err
	}

	if !s.checkOnGRC721Received(from, to, tid) {
		return ErrTransferToNonGRC721Receiver
	}

	return nil
}

// TransferFrom transfers a token from `from` to `to`. Same caller
// contract as SafeTransferFrom.
func (s *BasicNFT) TransferFrom(caller, from, to address, tid TokenID) error {
	if !s.isApprovedOrOwner(caller, tid) {
		return ErrCallerIsNotOwnerOrApproved
	}

	err := s.transfer(from, to, tid)
	if err != nil {
		return err
	}

	return nil
}

// Mints `tokenId` and transfers it to `to`.
func (s *BasicNFT) Mint(to address, tid TokenID) error {
	return s.mint(to, tid)
}

// Mints `tokenId` and transfers it to `to`. Also checks that
// contract recipients are using GRC721 protocol
func (s *BasicNFT) SafeMint(to address, tid TokenID) error {
	err := s.mint(to, tid)
	if err != nil {
		return err
	}

	if !s.checkOnGRC721Received(zeroAddress, to, tid) {
		return ErrTransferToNonGRC721Receiver
	}

	return nil
}

func (s *BasicNFT) Burn(tid TokenID) error {
	owner, err := s.OwnerOf(tid)
	if err != nil {
		return err
	}

	s.beforeTokenTransfer(owner, zeroAddress, tid, 1)

	tidStr := tid.String()
	s.tokenApprovals.Remove(tidStr)
	balance, err := s.BalanceOf(owner)
	if err != nil {
		return err
	}
	balance = overflow.Sub64p(balance, 1)

	ownerStr := owner.String()
	s.balances.Set(ownerStr, balance)
	s.owners.Remove(tidStr)

	chain.Emit(
		BurnEvent,
		"token", s.ID(),
		"from", ownerStr,
		"tokenId", tidStr,
	)

	s.afterTokenTransfer(owner, zeroAddress, tid, 1)

	return nil
}

/* Helper methods */

// Helper for SetApprovalForAll()
func (s *BasicNFT) setApprovalForAll(owner, operator address, approved bool) error {
	if owner == operator {
		return ErrApprovalToCurrentOwner
	}

	key := owner.String() + ":" + operator.String()
	s.operatorApprovals.Set(key, approved)

	chain.Emit(
		ApprovalForAllEvent,
		"token", s.ID(),
		"owner", owner.String(),
		"to", operator.String(),
		"approved", strconv.FormatBool(approved),
	)

	return nil
}

// Helper for TransferFrom() and SafeTransferFrom()
func (s *BasicNFT) transfer(from, to address, tid TokenID) error {
	if err := isValidAddress(from); err != nil {
		return ErrInvalidAddress
	}
	if err := isValidAddress(to); err != nil {
		return ErrInvalidAddress
	}

	if from == to {
		return ErrCannotTransferToSelf
	}

	owner, err := s.OwnerOf(tid)
	if err != nil {
		return err
	}
	if owner != from {
		return ErrTransferFromIncorrectOwner
	}

	s.beforeTokenTransfer(from, to, tid, 1)

	// Check that tokenId was not transferred by `beforeTokenTransfer`
	owner, err = s.OwnerOf(tid)
	if err != nil {
		return err
	}
	if owner != from {
		return ErrTransferFromIncorrectOwner
	}

	tidStr := tid.String()
	s.tokenApprovals.Remove(tidStr)
	fromBalance, err := s.BalanceOf(from)
	if err != nil {
		return err
	}
	toBalance, err := s.BalanceOf(to)
	if err != nil {
		return err
	}
	fromBalance = overflow.Sub64p(fromBalance, 1)
	toBalance = overflow.Add64p(toBalance, 1)

	fromStr := from.String()
	toStr := to.String()

	s.balances.Set(fromStr, fromBalance)
	s.balances.Set(toStr, toBalance)
	s.owners.Set(tidStr, to)

	chain.Emit(
		TransferEvent,
		"token", s.ID(),
		"from", fromStr,
		"to", toStr,
		"tokenId", tidStr,
	)

	s.afterTokenTransfer(from, to, tid, 1)

	return nil
}

// Helper for Mint() and SafeMint()
func (s *BasicNFT) mint(to address, tid TokenID) error {
	if err := isValidAddress(to); err != nil {
		return err
	}

	if s.exists(tid) {
		return ErrTokenIdAlreadyExists
	}

	s.beforeTokenTransfer(zeroAddress, to, tid, 1)

	// Check that tokenId was not minted by `beforeTokenTransfer`
	if s.exists(tid) {
		return ErrTokenIdAlreadyExists
	}

	toBalance, err := s.BalanceOf(to)
	if err != nil {
		return err
	}
	toBalance = overflow.Add64p(toBalance, 1)
	toStr := to.String()
	tidStr := tid.String()
	s.balances.Set(toStr, toBalance)
	s.owners.Set(tidStr, to)

	chain.Emit(
		MintEvent,
		"token", s.ID(),
		"to", toStr,
		"tokenId", tidStr,
	)

	s.afterTokenTransfer(zeroAddress, to, tid, 1)

	return nil
}

func (s *BasicNFT) isApprovedOrOwner(addr address, tid TokenID) bool {
	owner := s.owners.Get(tid.String())
	if owner == nil {
		return false
	}

	ownerAddr := owner.(address)
	if addr == ownerAddr || s.IsApprovedForAll(ownerAddr, addr) {
		return true
	}

	approved, err := s.GetApproved(tid)
	if err != nil {
		return false
	}

	return approved == addr
}

// Checks if token id already exists
func (s *BasicNFT) exists(tid TokenID) bool {
	return s.owners.Has(tid.String())
}

func (s *BasicNFT) beforeTokenTransfer(from, to address, firstTokenId TokenID, batchSize int64) {
	// TODO: Implementation
}

func (s *BasicNFT) afterTokenTransfer(from, to address, firstTokenId TokenID, batchSize int64) {
	// TODO: Implementation
}

func (s *BasicNFT) checkOnGRC721Received(from, to address, tid TokenID) bool {
	// TODO: Implementation
	return true
}

func (s *BasicNFT) RenderHome() (str string) {
	str += ufmt.Sprintf("# %s ($%s)\n\n", s.name, s.symbol)
	str += ufmt.Sprintf("* **Total supply**: %d\n", s.TokenCount())
	str += ufmt.Sprintf("* **Known accounts**: %d\n", s.balances.Size())

	return
}

// Getter returns an NFTGetter that yields a reader-only view of the NFT.
// Safe to register with cross-realm aggregators like tokenhub — readers
// only, no rlm-typed methods, so no cur can be captured via this surface.
func (n *BasicNFT) Getter() NFTGetter {
	return func() IGRC721Reader {
		return n
	}
}

package grc721

import (
	"chain"

	"gno.land/p/nt/avl/v0"
)

// metadataNFT represents an NFT with metadata extensions.
type metadataNFT struct {
	*BasicNFT
	extensions *avl.Tree // AVL tree for storing metadata extensions
}

// Ensure that metadataNFT implements the IGRC721MetadataOnchain interface.
var _ IGRC721MetadataOnchain = (*metadataNFT)(nil)

// NewNFTWithMetadata creates a new basic NFT with metadata extensions.
func NewNFTWithMetadata(_ int, rlm realm, name, symbol string) *metadataNFT {
	return &metadataNFT{
		BasicNFT:   NewBasicNFT(0, rlm, name, symbol),
		extensions: avl.NewTree(),
	}
}

// SetTokenMetadata sets metadata for a given token ID. The token must exist and
// caller must equal its owner; the owning realm's wrapper derives caller from
// rlm.Previous().Address() under IsCurrent (mirrors SetTokenRoyalty).
func (s *metadataNFT) SetTokenMetadata(caller address, tid TokenID, metadata Metadata) error {
	// Check that the token exists and the caller is its owner.
	owner, err := s.OwnerOf(tid)
	if err != nil {
		return err
	}
	if caller != owner {
		return ErrCallerIsNotOwner
	}

	// Set the metadata for the token ID in the extensions AVL tree
	s.extensions.Set(tid.String(), metadata)

	chain.Emit(
		MetadataUpdateEvent,
		"token", s.ID(),
		"tokenId", tid.String(),
	)

	return nil
}

// TokenMetadata retrieves metadata for a given token ID.
func (s *metadataNFT) TokenMetadata(tid TokenID) (Metadata, error) {
	// Retrieve metadata from the extensions AVL tree
	metadata := s.extensions.Get(tid.String())
	if metadata == nil {
		return Metadata{}, ErrInvalidTokenId
	}

	return metadata.(Metadata), nil
}

// Basic NFT methods forwarded to embedded BasicNFT

func (s *metadataNFT) Name() string {
	return s.BasicNFT.Name()
}

func (s *metadataNFT) Symbol() string {
	return s.BasicNFT.Symbol()
}

func (s *metadataNFT) TokenCount() int64 {
	return s.BasicNFT.TokenCount()
}

func (s *metadataNFT) BalanceOf(addr address) (int64, error) {
	return s.BasicNFT.BalanceOf(addr)
}

func (s *metadataNFT) OwnerOf(tid TokenID) (address, error) {
	return s.BasicNFT.OwnerOf(tid)
}

func (s *metadataNFT) TokenURI(tid TokenID) (string, error) {
	return s.BasicNFT.TokenURI(tid)
}

func (s *metadataNFT) SetTokenURI(caller address, tid TokenID, tURI TokenURI) (bool, error) {
	return s.BasicNFT.SetTokenURI(caller, tid, tURI)
}

func (s *metadataNFT) IsApprovedForAll(owner, operator address) bool {
	return s.BasicNFT.IsApprovedForAll(owner, operator)
}

func (s *metadataNFT) Approve(caller, to address, tid TokenID) error {
	return s.BasicNFT.Approve(caller, to, tid)
}

func (s *metadataNFT) GetApproved(tid TokenID) (address, error) {
	return s.BasicNFT.GetApproved(tid)
}

func (s *metadataNFT) SetApprovalForAll(caller, operator address, approved bool) error {
	return s.BasicNFT.SetApprovalForAll(caller, operator, approved)
}

func (s *metadataNFT) SafeTransferFrom(caller, from, to address, tid TokenID) error {
	return s.BasicNFT.SafeTransferFrom(caller, from, to, tid)
}

func (s *metadataNFT) TransferFrom(caller, from, to address, tid TokenID) error {
	return s.BasicNFT.TransferFrom(caller, from, to, tid)
}

func (s *metadataNFT) Mint(to address, tid TokenID) error {
	return s.BasicNFT.Mint(to, tid)
}

func (s *metadataNFT) SafeMint(to address, tid TokenID) error {
	return s.BasicNFT.SafeMint(to, tid)
}

func (s *metadataNFT) Burn(tid TokenID) error {
	return s.BasicNFT.Burn(tid)
}

func (s *metadataNFT) RenderHome() string {
	return s.BasicNFT.RenderHome()
}

package grc721

import (
	"testing"

	"gno.land/p/nt/testutils/v0"
	"gno.land/p/nt/uassert/v0"
)

func newDummyMetadataNFT(_ int, rlm realm) *metadataNFT {
	var nft *metadataNFT
	func(cur realm) {
		nft = NewNFTWithMetadata(0, cur, dummyNFTName, dummyNFTSymbol)
	}(cross(rlm))
	return nft
}

func TestSetMetadata(cur realm, t *testing.T) {
	// Create a new dummy NFT with metadata
	dummy := newDummyMetadataNFT(0, cur)
	if dummy == nil {
		t.Errorf("should not be nil")
	}

	// Define addresses for testing purposes
	addr1 := testutils.TestAddress("alice")
	addr2 := testutils.TestAddress("bob")

	// Define metadata attributes
	name := "test"
	description := "test"
	image := "test"
	imageData := "test"
	externalURL := "test"
	attributes := []Trait{}
	backgroundColor := "test"
	animationURL := "test"
	youtubeURL := "test"

	// Mint a new token for addr1
	dummy.mint(addr1, TokenID("1"))

	// Set metadata for token 1 as its owner (addr1)
	derr := dummy.SetTokenMetadata(addr1, TokenID("1"), Metadata{
		Name:            name,
		Description:     description,
		Image:           image,
		ImageData:       imageData,
		ExternalURL:     externalURL,
		Attributes:      attributes,
		BackgroundColor: backgroundColor,
		AnimationURL:    animationURL,
		YoutubeURL:      youtubeURL,
	})

	// Check if there was an error setting metadata
	uassert.NoError(t, derr, "Should not result in error")

	// Test case: invalid token ID. Setting metadata for a non-existent token fails.
	err := dummy.SetTokenMetadata(addr1, TokenID("3"), Metadata{
		Name:            name,
		Description:     description,
		Image:           image,
		ImageData:       imageData,
		ExternalURL:     externalURL,
		Attributes:      attributes,
		BackgroundColor: backgroundColor,
		AnimationURL:    animationURL,
		YoutubeURL:      youtubeURL,
	})

	uassert.ErrorIs(t, err, ErrInvalidTokenId)

	// Test case: caller is not the owner. Setting metadata from a non-owner (addr2) fails.
	cerr := dummy.SetTokenMetadata(addr2, TokenID("1"), Metadata{
		Name:            name,
		Description:     description,
		Image:           image,
		ImageData:       imageData,
		ExternalURL:     externalURL,
		Attributes:      attributes,
		BackgroundColor: backgroundColor,
		AnimationURL:    animationURL,
		YoutubeURL:      youtubeURL,
	})

	uassert.ErrorIs(t, cerr, ErrCallerIsNotOwner)

	// Retrieve metadata for token 1
	dummyMetadata, err := dummy.TokenMetadata(TokenID("1"))
	uassert.NoError(t, err, "Metadata error")

	// Check if metadata attributes match expected values
	uassert.Equal(t, image, dummyMetadata.Image)
	uassert.Equal(t, imageData, dummyMetadata.ImageData)
	uassert.Equal(t, externalURL, dummyMetadata.ExternalURL)
	uassert.Equal(t, description, dummyMetadata.Description)
	uassert.Equal(t, name, dummyMetadata.Name)
	uassert.Equal(t, len(attributes), len(dummyMetadata.Attributes))
	uassert.Equal(t, backgroundColor, dummyMetadata.BackgroundColor)
	uassert.Equal(t, animationURL, dummyMetadata.AnimationURL)
	uassert.Equal(t, youtubeURL, dummyMetadata.YoutubeURL)
}

package grc721

import (
	"math/overflow"

	"gno.land/p/nt/avl/v0"
)

// royaltyNFT represents a non-fungible token (NFT) with royalty functionality.
type royaltyNFT struct {
	*metadataNFT                   // Embedding metadataNFT for NFT functionality
	tokenRoyaltyInfo     *avl.Tree // AVL tree to store royalty information for each token
	maxRoyaltyPercentage int64     // maxRoyaltyPercentage represents the maximum royalty percentage that can be charged every sale
}

// Ensure that royaltyNFT implements the IGRC2981 interface.
var _ IGRC2981 = (*royaltyNFT)(nil)

// NewNFTWithRoyalty creates a new royalty NFT with the specified name, symbol, and royalty calculator.
func NewNFTWithRoyalty(_ int, rlm realm, name, symbol string) *royaltyNFT {
	return &royaltyNFT{
		metadataNFT:          NewNFTWithMetadata(0, rlm, name, symbol),
		tokenRoyaltyInfo:     avl.NewTree(),
		maxRoyaltyPercentage: 100,
	}
}

// SetTokenRoyalty sets the royalty information for a specific token ID.
// caller must equal the token's owner; the owning realm's wrapper
// derives caller from rlm.Previous().Address() under IsCurrent.
func (r *royaltyNFT) SetTokenRoyalty(caller address, tid TokenID, royaltyInfo RoyaltyInfo) error {
	// Validate the payment address
	if err := isValidAddress(royaltyInfo.PaymentAddress); err != nil {
		return ErrInvalidRoyaltyPaymentAddress
	}

	// Check if royalty percentage exceeds maxRoyaltyPercentage
	if royaltyInfo.Percentage > r.maxRoyaltyPercentage {
		return ErrInvalidRoyaltyPercentage
	}

	// Check if the caller is the owner of the token
	owner, err := r.metadataNFT.OwnerOf(tid)
	if err != nil {
		return err
	}
	if caller != owner {
		return ErrCallerIsNotOwner
	}

	// Set royalty information for the token
	r.tokenRoyaltyInfo.Set(tid.String(), royaltyInfo)

	return nil
}

// RoyaltyInfo returns the royalty information for the given token ID and sale price.
func (r *royaltyNFT) RoyaltyInfo(tid TokenID, salePrice int64) (address, int64, error) {
	// Retrieve royalty information for the token
	val := r.tokenRoyaltyInfo.Get(tid.String())
	if val == nil {
		return "", 0, ErrInvalidTokenId
	}

	royaltyInfo := val.(RoyaltyInfo)

	// Calculate royalty amount
	royaltyAmount, _ := r.calculateRoyaltyAmount(salePrice, royaltyInfo.Percentage)

	return royaltyInfo.PaymentAddress, royaltyAmount, nil
}

func (r *royaltyNFT) calculateRoyaltyAmount(salePrice, percentage int64) (int64, error) {
	royaltyAmount := overflow.Mul64p(salePrice, percentage) / 100
	return royaltyAmount, nil
}

package grc721

import (
	"testing"

	"gno.land/p/nt/testutils/v0"
	"gno.land/p/nt/uassert/v0"
)

func newDummyRoyaltyNFT(_ int, rlm realm) *royaltyNFT {
	var nft *royaltyNFT
	func(cur realm) {
		nft = NewNFTWithRoyalty(0, cur, dummyNFTName, dummyNFTSymbol)
	}(cross(rlm))
	return nft
}

func TestSetTokenRoyalty(cur realm, t *testing.T) {
	dummy := newDummyRoyaltyNFT(0, cur)
	uassert.True(t, dummy != nil, "should not be nil")

	addr1 := testutils.TestAddress("alice")
	addr2 := testutils.TestAddress("bob")

	paymentAddress := testutils.TestAddress("john")
	percentage := int64(10) // 10%

	salePrice := int64(1000)
	expectRoyaltyAmount := int64(100)

	dummy.mint(addr1, TokenID("1"))

	derr := dummy.SetTokenRoyalty(addr1, TokenID("1"), RoyaltyInfo{
		PaymentAddress: paymentAddress,
		Percentage:     percentage,
	})
	uassert.NoError(t, derr, "Should not result in error")

	// Test case: Invalid token ID
	err := dummy.SetTokenRoyalty(addr1, TokenID("3"), RoyaltyInfo{
		PaymentAddress: paymentAddress,
		Percentage:     percentage,
	})
	uassert.ErrorIs(t, err, ErrInvalidTokenId)

	// Test case: Invalid payment address
	aerr := dummy.SetTokenRoyalty(addr1, TokenID("4"), RoyaltyInfo{
		PaymentAddress: address("###"), // invalid address
		Percentage:     percentage,
	})
	uassert.ErrorIs(t, aerr, ErrInvalidRoyaltyPaymentAddress)

	// Test case: Invalid percentage
	perr := dummy.SetTokenRoyalty(addr1, TokenID("5"), RoyaltyInfo{
		PaymentAddress: paymentAddress,
		Percentage:     int64(200), // over maxRoyaltyPercentage
	})
	uassert.ErrorIs(t, perr, ErrInvalidRoyaltyPercentage)

	// addr2 is not the owner.
	cerr := dummy.SetTokenRoyalty(addr2, TokenID("1"), RoyaltyInfo{
		PaymentAddress: paymentAddress,
		Percentage:     percentage,
	})
	uassert.ErrorIs(t, cerr, ErrCallerIsNotOwner)

	dummyPaymentAddress, dummyRoyaltyAmount, rerr := dummy.RoyaltyInfo(TokenID("1"), salePrice)
	uassert.NoError(t, rerr, "RoyaltyInfo error")
	uassert.Equal(t, paymentAddress, dummyPaymentAddress)
	uassert.Equal(t, expectRoyaltyAmount, dummyRoyaltyAmount)
}

package grc721

// IGRC721Reader is the read-only view of an NFT. Safe to receive across
// realm boundaries — has no rlm-typed methods, so a malicious impl can
// only lie about read results (data-integrity issue), not capture cur.
//
// Writes are concrete methods on *BasicNFT / *metadataNFT / *royaltyNFT
// only — there is no IGRC721 writer interface. The owning realm should
// hold the concrete *BasicNFT in an unexported package var and expose
// public rlm-validating wrappers like:
//
//	func TransferFrom(cur realm, from, to address, tid TokenID) error {
//		caller := cur.Previous().Address()
//		return nft.TransferFrom(caller, from, to, tid)
//	}
//
// This is the Reader/Writer split — stronger than the Authority-pattern
// because the writer interface doesn't exist at all, so no realm author
// can accidentally expose it. See `r/demo/foo721` for the canonical
// wrapper pattern.
type IGRC721Reader interface {
	Name() string
	Symbol() string
	TokenCount() int64
	BalanceOf(owner address) (int64, error)
	OwnerOf(tid TokenID) (address, error)
	GetApproved(tid TokenID) (address, error)
	IsApprovedForAll(owner, operator address) bool
}

type (
	TokenID  string
	TokenURI string
)

func (t TokenID) String() string  { return string(t) }
func (t TokenURI) String() string { return string(t) }

const (
	MintEvent           = "Mint"
	BurnEvent           = "Burn"
	TransferEvent       = "Transfer"
	ApprovalEvent       = "Approval"
	ApprovalForAllEvent = "ApprovalForAll"
	TokenURIUpdateEvent = "TokenUriUpdate"
	MetadataUpdateEvent = "MetadataUpdate"
)

// NFTGetter returns a reader-only view of an NFT. Aggregators (such as
// tokenhub) register and dispatch NFTGetters; the reader-only return
// type means even a malicious aggregator can't be used to leak cur.
type NFTGetter func() IGRC721Reader

